+              _server->remoteEndpointString(hdl).c_str(), publisher->get_topic_name(),
+              publisher->get_subscription_count(), channelId);
+
+  clientPublications.erase(it2);
+  if (clientPublications.empty()) {
+    _clientAdvertisedTopics.erase(it);
